import { GoogleGenAI, Type } from "@google/genai";
import { TripFormData, Itinerary, TravelMode, MarketInsight, GroundingSource, Stop } from "../types";
import { GEMINI_MODEL, GEMINI_FLASH_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to clean JSON string from Markdown or extra text
const cleanJsonString = (text: string): string => {
    let clean = text.trim();
    // Remove markdown code blocks if present (json or just backticks)
    clean = clean.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '');

    // Attempt to extract the first JSON object if there's surrounding text
    const firstBrace = clean.indexOf('{');
    const lastBrace = clean.lastIndexOf('}');

    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
        clean = clean.substring(firstBrace, lastBrace + 1);
    }

    return clean;
};

// Integrated from real-keywords-collector/keywords.txt
const KEYWORD_MARKET_DATA = `
TARGET NICHE KEYWORDS (Use these for Search Validation):
- gay massage, sensual massage, erotic massage
- male massage therapist, male massage near me, gay massage therapist
- male body massage, massage male to male, male massage therapy
- gay friendly massage, gay spa massage, LGBTQ massage therapist
- massage for gay men, man on man massage, LGBTQ friendly massage
- gay deep tissue massage, gay couples massage, gay sports massage
- male to male massage therapy, gay Swedish massage
- professional male massage, male aromatherapy massage
- gay Thai massage, certified male massage therapist
`;

const isQuotaError = (error: any): boolean => {
    return (
        error.status === 429 || 
        error.code === 429 || 
        error.status === 503 || 
        error.code === 503 ||
        (error.message && (error.message.includes('429') || error.message.includes('quota') || error.message.includes('RESOURCE_EXHAUSTED') || error.message.includes('overloaded')))
    );
};

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();
  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

  const mandatoryStopsText = data.mandatoryStops.length > 0
    ? data.mandatoryStops.map(s => `${s.location}${s.arrivalDate ? ` (Arrive: ${s.arrivalDate})` : ''}`).join(', ')
    : 'None';

  const originText = data.origin ? data.origin : "Flexible/User-Decided (Suggest a logical start based on stops/market)";
  const destinationText = data.destination ? data.destination : "Flexible/User-Decided (Suggest a logical end)";
  const driveConstraint = data.maxDriveHours > 0 ? `${data.maxDriveHours} hours per leg` : "Auto-optimized for best experience";

  const routePrefMap: Record<string, string> = {
    'fastest': 'Prioritize efficiency and highways (Fastest Route). Minimize travel time.',
    'scenic': 'Prioritize scenic byways, nature views, and enjoyable driving roads. Avoid boring interstates. Select routes known for natural beauty even if they take longer.',
    'avoidTolls': 'Strictly avoid toll roads and paid highways.'
  };
  const routeConstraint = routePrefMap[data.routePreference] || routePrefMap['fastest'];

  const prompt = `
    TODAY'S DATE: ${today}
    ROLE: You are a specialized Logistics & Market Analyst for the male wellness sector.

    GOAL: Create a high-revenue road trip itinerary starting from ${originText} and ending at ${destinationText}${data.destinationDate ? ` (Arrival by: ${data.destinationDate})` : ''}.

    CONSTRAINTS:
    - Max Drive: ${driveConstraint}.
    - Route Style: ${routeConstraint}
    - Mandatory Stops: ${mandatoryStopsText}.
    - Total Stops: Approx ${data.numberOfStops}.
    - Strategy: ${isAlternative ? 'Explore high-growth secondary markets (blue ocean strategy).' : 'Stick to established high-volume hubs (red ocean strategy).'}

    ${KEYWORD_MARKET_DATA}

    STRICT RULES FOR 'nightsToStay' (Classificação Final Definitiva):
    - **Score 90-100 (Platinum)**: 3 Nights.
    - **Score 75-89 (Gold)**: 2 Nights.
    - **Score 60-74 (Silver)**: 1 Night.
    - **Score < 60 (Bronze)**: 0 Nights (Day stop / Lunch only).
    - **Safety Override**: If search indicates active safety risks for LGBTQ+ travelers in the area, force 'nightsToStay' = 0.

    EXECUTION STEPS:
    1. **Route Logic**: Plan a feasible driving route. If Origin/Destination are "Flexible", suggest major hubs near the Mandatory Stops.
    2. **Market Validation**: Use Google Search to check demand in intermediate cities.
    3. **Evidence-Based Justification**: Cite specific events/venues.
  `;

  const itinerarySchema = {
    type: Type.OBJECT,
    properties: {
      routeName: { type: Type.STRING },
      totalDistance: { type: Type.STRING },
      totalDuration: { type: Type.STRING },
      summary: { type: Type.STRING },
      stops: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.NUMBER },
            city: { type: Type.STRING },
            activity: { type: Type.STRING },
            profitabilityJustification: { type: Type.STRING },
            demandScore: { type: Type.NUMBER },
            trendVelocity: { type: Type.STRING },
            clusterInfo: {
              type: Type.OBJECT,
              properties: {
                anchorCity: { type: Type.STRING },
                clusterVolume: { type: Type.STRING },
              },
            },
            nightsToStay: { type: Type.NUMBER },
            travelTimeFromPrev: { type: Type.STRING },
            travelToNext: { type: Type.STRING },
            coordinates: {
              type: Type.OBJECT,
              properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER },
              },
            },
          },
          required: ["day", "city", "activity", "demandScore", "nightsToStay"],
        },
      },
    },
    required: ["routeName", "stops", "summary"],
  };

  const modelConfig = {
    maxOutputTokens: 8192,
    tools: [{ googleSearch: {} }],
    responseMimeType: "application/json",
    responseSchema: itinerarySchema,
  };

  try {
    let response;
    try {
        response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: modelConfig,
        });
    } catch (error: any) {
        // Retry with Flash model on quota error, 500 error, or generic XHR/RPC failures
        if (isQuotaError(error) || error.code === 500 || error.status === 500 || error.message?.includes('Rpc failed')) {
            console.warn("Pro model error (quota or server), falling back to Flash model.");
            response = await ai.models.generateContent({
                model: GEMINI_FLASH_MODEL,
                contents: prompt,
                config: modelConfig,
            });
        } else {
            throw error;
        }
    }

    const text = response.text;
    if (!text) {
        throw new Error("No content generated");
    }

    const cleanText = cleanJsonString(text);
    const result = JSON.parse(cleanText) as Itinerary;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const globalSources: GroundingSource[] = [];
    if (chunks) {
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                globalSources.push({
                    title: chunk.web.title || "Reference Source",
                    uri: chunk.web.uri
                });
            }
        });
    }
    result.sources = Array.from(new Map(globalSources.map(s => [s.uri, s])).values());

    // Precise Source Mapping
    result.stops = result.stops.map(stop => {
        const cityKeywords = stop.city.toLowerCase().split(',')[0].trim();
        const stopSources = globalSources.filter(s => 
            s.title.toLowerCase().includes(cityKeywords) || 
            s.uri.toLowerCase().includes(cityKeywords.replace(/\s/g, ''))
        );
        return {
            ...stop,
            stopSources: stopSources.length > 0 ? Array.from(new Map(stopSources.map(s => [s.uri, s])).values()) : undefined
        };
    });

    result.startDate = data.startDate;
    result.origin = data.origin || result.stops[0]?.city || "Unknown Start";
    result.destination = data.destination || result.stops[result.stops.length - 1]?.city || "Unknown End";

    result.stops.sort((a, b) => a.day - b.day);

    return result;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error(error.message || "Route calculation failed. Check your API key and network.");
  }
};

