    };

    const modelConfig = {
        maxOutputTokens: 8192,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: insightSchema,
    };

    try {
      let response;
      try {
          response = await ai.models.generateContent({
            model: GEMINI_MODEL,
            contents: prompt,
            config: modelConfig,
          });
      } catch (error: any) {
        if (isQuotaError(error)) {
            console.warn("Pro model error, falling back to Flash model.");
            response = await ai.models.generateContent({
                model: GEMINI_FLASH_MODEL,
                contents: prompt,
                config: modelConfig,
            });
        } else {
            throw error;
        }
      }

      const text = response.text;
      if (!text) {
          throw new Error("No insights generated");
      }

      const cleanText = cleanJsonString(text);
      let result: MarketInsight;

      try {
        result = JSON.parse(cleanText) as MarketInsight;
      } catch (e) {
        console.error("JSON Parse Error. Raw Text:", text);
        console.error("Cleaned Text:", cleanText);
        throw e;
      }

      return { ...result, lastUpdated: today };
